import type { Room, Option, User } from "./api";

const MOCK_ROOMS = new Map<string, Room>();
let mockId = 0;
const id = () => `mock-${++mockId}`;

function generateCode(): string {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  let code = "";
  for (let i = 0; i < 6; i++) code += chars[Math.floor(Math.random() * chars.length)];
  return code;
}

export function mockCreateRoom(name: string): { room: Room; user: User } {
  let code = generateCode();
  while (MOCK_ROOMS.has(code)) code = generateCode();

  const room: Room = {
    id: id(),
    code,
    hostId: id(),
    status: "waiting",
    endTime: null,
    options: [],
  };
  MOCK_ROOMS.set(code, room);

  const user: User = {
    id: room.hostId,
    roomId: room.id,
    name,
    hasVoted: false,
  };
  return { room, user };
}

export function mockJoinRoom(code: string, name: string): { room: Room; user: User } {
  const room = MOCK_ROOMS.get(code.toUpperCase());
  if (!room) throw new Error("Room not found");
  if (room.status === "finished") throw new Error("Room has ended");

  const user: User = {
    id: id(),
    roomId: room.id,
    name,
    hasVoted: false,
  };
  return { room, user };
}

export function mockGetRoom(code: string): Room | undefined {
  const room = MOCK_ROOMS.get(code.toUpperCase());
  if (!room) return undefined;
  if (room.status === "voting" && room.endTime) {
    const end = new Date(room.endTime).getTime();
    if (Date.now() >= end) {
      room.status = "finished";
    }
  }
  return room;
}

const MAX_OPTIONS = 4;

export function mockAddOption(roomCode: string, name: string): Option {
  const room = MOCK_ROOMS.get(roomCode.toUpperCase());
  if (!room) throw new Error("Room not found");
  if (room.options.length >= MAX_OPTIONS) throw new Error("Maximum 4 suggestions");
  const existing = room.options.find(
    (o) => o.name.toLowerCase() === name.toLowerCase().trim()
  );
  if (existing) throw new Error("Option already exists");
  const option: Option = {
    id: id(),
    roomId: room.id,
    name: name.trim(),
    voteCount: 0,
  };
  room.options = [...room.options, option];
  return option;
}

export function mockVote(roomCode: string, optionId: string, userId: string): void {
  const room = MOCK_ROOMS.get(roomCode.toUpperCase());
  if (!room) throw new Error("Room not found");
  const user = { id: userId, hasVoted: true }; // simplified
  const option = room.options.find((o) => o.id === optionId);
  if (!option) throw new Error("Option not found");
  option.voteCount++;
  room.options = [...room.options];
}

const MOCK_ADDRESSES = [
  "123 Main St",
  "456 Oak Ave",
  "789 Elm Blvd",
  "321 Pine Rd",
];

export function mockStartTimer(
  roomCode: string,
  durationSeconds: number,
  _latitude?: number,
  _longitude?: number
): void {
  const room = MOCK_ROOMS.get(roomCode.toUpperCase());
  if (!room) throw new Error("Room not found");
  // Simulate Google Places: enrich options with addresses
  room.options = room.options.map((o, i) => ({
    ...o,
    address: MOCK_ADDRESSES[i] ?? `${100 + i} Local St`,
  }));
  room.status = "voting";
  room.endTime = new Date(Date.now() + durationSeconds * 1000).toISOString();
}

export function mockRestartRoom(roomCode: string): Room {
  const room = MOCK_ROOMS.get(roomCode.toUpperCase());
  if (!room) throw new Error("Room not found");
  room.status = "waiting";
  room.endTime = null;
  room.options = room.options.map(({ id, roomId, name }) => ({
    id,
    roomId,
    name,
    voteCount: 0,
  }));
  return { ...room };
}
